import { useState, useEffect } from 'react';
import { Card, Stack, Row, Text, Container } from '@ggui-ai/design/primitives';

interface ForecastDay {
  dayName: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  temperature?: number;
  condition?: string;
  humidity?: number;
  windSpeed?: number;
  location?: string;
  forecast?: ForecastDay[];
  unit?: 'C' | 'F';
  onSubmit?: (data: unknown) => void;
}

export default function GeneratedComponent({
  temperature = 22,
  condition = 'Partly Cloudy',
  humidity = 65,
  windSpeed = 12,
  location = 'San Francisco, CA',
  forecast = [
    { dayName: 'Mon', icon: '☀️', high: 24, low: 18 },
    { dayName: 'Tue', icon: '⛅', high: 23, low: 17 },
    { dayName: 'Wed', icon: '🌧️', high: 20, low: 15 },
    { dayName: 'Thu', icon: '☁️', high: 21, low: 16 },
    { dayName: 'Fri', icon: '☀️', high: 25, low: 19 },
  ],
  unit = 'C',
  onSubmit,
}: Props) {
  const getWeatherEmoji = (cond: string): string => {
    const condLower = cond.toLowerCase();
    if (condLower.includes('sunny') || condLower.includes('clear')) return '☀️';
    if (condLower.includes('cloud')) return '☁️';
    if (condLower.includes('partly')) return '⛅';
    if (condLower.includes('rain') || condLower.includes('rainy')) return '🌧️';
    if (condLower.includes('storm') || condLower.includes('thunder')) return '⛈️';
    if (condLower.includes('snow')) return '❄️';
    if (condLower.includes('fog') || condLower.includes('mist')) return '🌫️';
    if (condLower.includes('wind')) return '💨';
    return '🌤️';
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-md, 16px)">
      <Card 
        padding="var(--ggui-spacing-lg, 24px)" 
        shadow="md"
        style={{
          background: 'linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))',
          borderTop: '4px solid var(--ggui-color-primary-500, #0ea5e9)',
        }}
      >
        <Stack direction="vertical" gap={24} align="stretch">
          {/* Location Header */}
          <div style={{ paddingBottom: 'var(--ggui-spacing-sm, 8px)', borderBottom: '1px solid var(--ggui-color-primary-200, #bae6fd)' }}>
            <Text 
              variant="label" 
              color="var(--ggui-color-primary-700, #0369a1)"
              style={{ fontSize: 'var(--ggui-typography-fontSize-sm, 14px)' }}
            >
              {location}
            </Text>
          </div>

          {/* Current Weather Section */}
          <Stack direction="vertical" gap={16} align="center">
            {/* Temperature - Large and Prominent */}
            <div style={{ textAlign: 'center' }}>
              <div style={{
                fontSize: 'var(--ggui-typography-fontSize-4xl, 36px)',
                fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
                color: 'var(--ggui-color-primary-900, #0c4a6e)',
                lineHeight: 1.2,
              }}>
                {temperature}°{unit}
              </div>
            </div>

            {/* Condition with Emoji */}
            <div style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              gap: 'var(--ggui-spacing-sm, 8px)',
            }}>
              <div style={{
                fontSize: '3rem',
                lineHeight: 1,
              }}>
                {getWeatherEmoji(condition)}
              </div>
              <Text 
                variant="body"
                color="var(--ggui-color-primary-800, #075985)"
                weight="semibold"
                style={{ fontSize: 'var(--ggui-typography-fontSize-lg, 18px)' }}
              >
                {condition}
              </Text>
            </div>

            {/* Humidity and Wind Speed */}
            <Row 
              gap={24}
              justify="center"
              style={{
                width: '100%',
                marginTop: 'var(--ggui-spacing-md, 16px)',
              }}
            >
              {/* Humidity */}
              <div style={{
                flex: 1,
                padding: 'var(--ggui-spacing-md, 16px)',
                backgroundColor: 'var(--ggui-color-surface, #ffffff)',
                borderRadius: 'var(--ggui-radius-lg, 12px)',
                border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                textAlign: 'center',
              }}>
                <Text 
                  variant="caption"
                  color="var(--ggui-color-text-secondary, #6b7280)"
                  style={{ fontSize: 'var(--ggui-typography-fontSize-xs, 12px)' }}
                >
                  Humidity
                </Text>
                <div style={{
                  fontSize: 'var(--ggui-typography-fontSize-2xl, 24px)',
                  fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                  marginTop: 'var(--ggui-spacing-xs, 4px)',
                }}>
                  {humidity}%
                </div>
              </div>

              {/* Wind Speed */}
              <div style={{
                flex: 1,
                padding: 'var(--ggui-spacing-md, 16px)',
                backgroundColor: 'var(--ggui-color-surface, #ffffff)',
                borderRadius: 'var(--ggui-radius-lg, 12px)',
                border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                textAlign: 'center',
              }}>
                <Text 
                  variant="caption"
                  color="var(--ggui-color-text-secondary, #6b7280)"
                  style={{ fontSize: 'var(--ggui-typography-fontSize-xs, 12px)' }}
                >
                  Wind Speed
                </Text>
                <div style={{
                  fontSize: 'var(--ggui-typography-fontSize-2xl, 24px)',
                  fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                  marginTop: 'var(--ggui-spacing-xs, 4px)',
                }}>
                  {windSpeed} km/h
                </div>
              </div>
            </Row>
          </Stack>

          {/* Divider */}
          <div style={{
            height: '1px',
            backgroundColor: 'var(--ggui-color-primary-200, #bae6fd)',
            margin: 'var(--ggui-spacing-md, 16px) 0',
          }} />

          {/* 5-Day Forecast Section */}
          <Stack direction="vertical" gap={8}>
            <Text 
              variant="label"
              color="var(--ggui-color-primary-900, #0c4a6e)"
              weight="semibold"
              style={{ fontSize: 'var(--ggui-typography-fontSize-sm, 14px)' }}
            >
              5-Day Forecast
            </Text>

            {/* Forecast Strip - Horizontal Scrollable */}
            <div style={{
              display: 'flex',
              gap: 'var(--ggui-spacing-sm, 8px)',
              overflowX: 'auto',
              overflowY: 'hidden',
              paddingBottom: 'var(--ggui-spacing-xs, 4px)',
              WebkitOverflowScrolling: 'touch',
            }}>
              {forecast.map((day, idx) => (
                <div
                  key={day.dayName + idx}
                  style={{
                    flex: '0 0 auto',
                    minWidth: 'clamp(80px, 20%, 100px)',
                    padding: 'var(--ggui-spacing-md, 16px)',
                    backgroundColor: 'var(--ggui-color-surface, #ffffff)',
                    border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                    borderRadius: 'var(--ggui-radius-lg, 12px)',
                    textAlign: 'center',
                    transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
                    cursor: 'pointer',
                  }}
                  onMouseEnter={(e) => {
                    const target = e.currentTarget as HTMLDivElement;
                    target.style.boxShadow = 'var(--ggui-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
                    target.style.borderColor = 'var(--ggui-color-primary-400, #38bdf8)';
                    target.style.backgroundColor = 'var(--ggui-color-primary-50, #f0f9ff)';
                  }}
                  onMouseLeave={(e) => {
                    const target = e.currentTarget as HTMLDivElement;
                    target.style.boxShadow = 'none';
                    target.style.borderColor = 'var(--ggui-color-primary-200, #bae6fd)';
                    target.style.backgroundColor = 'var(--ggui-color-surface, #ffffff)';
                  }}
                >
                  {/* Day Name */}
                  <Text 
                    variant="label"
                    color="var(--ggui-color-primary-700, #0369a1)"
                    weight="semibold"
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-xs, 12px)',
                      marginBottom: 'var(--ggui-spacing-xs, 4px)',
                    }}
                  >
                    {day.dayName}
                  </Text>

                  {/* Weather Icon */}
                  <div style={{
                    fontSize: '2rem',
                    lineHeight: 1,
                    margin: 'var(--ggui-spacing-xs, 4px) 0',
                  }}>
                    {day.icon}
                  </div>

                  {/* Temps */}
                  <div style={{
                    display: 'flex',
                    justifyContent: 'center',
                    gap: 'var(--ggui-spacing-xs, 4px)',
                    marginTop: 'var(--ggui-spacing-xs, 4px)',
                    fontSize: 'var(--ggui-typography-fontSize-xs, 12px)',
                  }}>
                    <span style={{
                      fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                      color: 'var(--ggui-color-primary-600, #0284c7)',
                    }}>
                      {day.high}°
                    </span>
                    <span style={{
                      color: 'var(--ggui-color-text-secondary, #6b7280)',
                    }}>
                      {day.low}°
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import { Container, Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city?: string;
  temperature?: number;
  condition?: string;
  humidity?: number;
  windSpeed?: number;
  forecast?: ForecastItem[];
  onSubmit?: (data: unknown) => void;
}

export default function GeneratedComponent({
  city = "Unknown City",
  temperature = 20,
  condition = "Partly Cloudy",
  humidity = 60,
  windSpeed = 15,
  forecast = [
    { day: "Mon", icon: "☀️", high: 25, low: 15 },
    { day: "Tue", icon: "☁️", high: 22, low: 14 },
    { day: "Wed", icon: "🌧️", high: 18, low: 10 },
    { day: "Thu", icon: "⛈️", high: 20, low: 12 },
    { day: "Fri", icon: "☀️", high: 27, low: 16 },
  ],
  onSubmit
}: Props) {
  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-md, 16px)">
      <Card
        padding="var(--ggui-spacing-lg, 24px)"
        shadow="md"
        aria-label="Weather Card"
        style={{
          backgroundColor: 'var(--ggui-color-surface, #ffffff)',
          borderRadius: 'var(--ggui-radius-lg, 12px)',
          borderColor: 'var(--ggui-color-gray-200, #e5e7eb)',
          borderWidth: '1px',
          borderStyle: 'solid',
        }}
      >
        <Stack direction="vertical" gap="var(--ggui-spacing-lg, 24px)">
          {/* Current Weather */}
          <Stack direction="vertical" align="center" gap="var(--ggui-spacing-sm, 8px)">
            <Text
              variant="h3"
              weight="semibold"
              color="var(--ggui-color-text-primary, #111827)"
              style={{
                fontSize: 'var(--ggui-typography-fontSize-2xl, 24px)',
                lineHeight: '1.2',
              }}
            >
              {city}
            </Text>
            <Text
              color="var(--ggui-color-primary-600, #0284c7)"
              style={{
                fontSize: 'var(--ggui-typography-fontSize-4xl, 36px)',
                fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
                lineHeight: '1',
              }}
            >
              {temperature}°C
            </Text>
            <Row gap="var(--ggui-spacing-sm, 8px)" align="center">
              <Text
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-xl, 20px)',
                  lineHeight: '1',
                }}
              >
                {condition === 'Sunny' ? '☀️' :
                 condition === 'Partly Cloudy' ? '⛅' :
                 condition === 'Cloudy' ? '☁️' :
                 condition === 'Rainy' ? '🌧️' :
                 condition === 'Thunderstorm' ? '⛈️' :
                 condition === 'Snowy' ? '❄️' : '❓'}
              </Text>
              <Text
                variant="h4"
                weight="medium"
                color="var(--ggui-color-text-secondary, #6b7280)"
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-lg, 18px)',
                }}
              >
                {condition}
              </Text>
            </Row>
            <Row gap="var(--ggui-spacing-lg, 24px)">
              <Text variant="body" color="var(--ggui-color-text-secondary, #6b7280)">
                Humidity: <Text weight="semibold">{humidity}%</Text>
              </Text>
              <Text variant="body" color="var(--ggui-color-text-secondary, #6b7280)">
                Wind: <Text weight="semibold">{windSpeed} km/h</Text>
              </Text>
            </Row>
          </Stack>

          {/* Separator */}
          <div style={{
            height: '1px',
            backgroundColor: 'var(--ggui-color-gray-200, #e5e7eb)',
            margin: 'var(--ggui-spacing-md, 16px) 0',
          }} />

          {/* 5-Day Forecast */}
          <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-sm, 8px)">
            {forecast.map((item, index) => (
              <Stack
                key={index}
                direction="vertical"
                align="center"
                gap="var(--ggui-spacing-xs, 4px)"
                style={{ flex: 1, minWidth: '50px' }}
              >
                <Text variant="caption" weight="medium" color="var(--ggui-color-text-secondary, #6b7280)">
                  {item.day}
                </Text>
                <Text
                  style={{
                    fontSize: 'var(--ggui-typography-fontSize-xl, 20px)',
                    lineHeight: '1',
                  }}
                >
                  {item.icon}
                </Text>
                <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-text-primary, #111827)">
                  {item.high}°
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-text-secondary, #6b7280)">
                  {item.low}°
                </Text>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
